<template>
	<div>
        <div id="echartContainer" style="width:500px; height:500px"></div>
        <el-button class="goButton" @click="goDetail">查看图表</el-button>
    </div>
</template>

<script>
// @ is an alias to /src
// import HelloWorld from '@/components/HelloWorld.vue'
// import api from '../utils/api'
// import marked from 'marked'
import echarts from 'echarts'
export default {
	name: 'artical',
	data() {
		return {
            articalContent:'',
            modelList: {
                rent: 0,
                eating: 0,
                bdbing: 440,
                roading: 220,
                whiteTicket: 0,
                others: 0
            }
		}
	},
	methods: {
		goDetail () {
            let myChart = echarts.init(document.getElementById('echartContainer'))
            let echartsTempData = []
            for (const key in this.modelList) {
                if (this.modelList.hasOwnProperty(key)) {
                    echartsTempData.push({name:key,value:this.modelList[key]})
                }
            }
            // 绘制图表
            myChart.setOption({
                series: {
                    type: 'pie',
                    data: echartsTempData
            }});
        }
	},
	computed: {
	},
	mounted() {
	},
}

</script>
